import * as fs from "fs";
import Handlebars from "handlebars";
import { bindingRegex } from "./TemplateParser";


Handlebars.registerHelper("sub", function (a: number, b: number) {
  return a - b;
});

Handlebars.registerHelper("add", function (a: number, b: number) {
  return a + b;
});

Handlebars.registerHelper("gt", function (a: number, b: number) {
  return a > b;
});

Handlebars.registerHelper("lt", function (a: number, b: number) {
  return a < b;
});

Handlebars.registerHelper("eq", function (a: number, b: number) {
  return a === b;
});

Handlebars.registerHelper("and", function (a: boolean, b: boolean) {
  return a && b;
});

Handlebars.registerHelper("or", function (a: boolean, b: boolean) {
  return a || b;
});

Handlebars.registerHelper("not", function (a: boolean) {
  return !a;
});



Handlebars.registerHelper("innerFieldNames", function (array: any[]) {
  if (!array) {
    console.error("Array is undefined. Cannot get inner keys.");
    console.error(array);
    return [];
  }
  let field_names=[];
  for (let i = 0; i < array.length; i++) {
    if (array[i]["field_name"]) {
      field_names.push(array[i]["field_name"]);
    }
  }

  return field_names;

});

Handlebars.registerHelper("innerFieldDescriptions", function (obj: any) {

});

// Register a "keys" helper to get the keys of an object
Handlebars.registerHelper("keys", function (obj: Record<string, any>) {
  if (!obj) {
    console.error("Object is undefined. Cannot get keys.");
    console.error(obj);
    return [];
  }
  return Object.keys(obj);
});

// Register a "lookup" helper to retrieve a value from an object by key
Handlebars.registerHelper(
  "lookup",
  function (obj: Record<string, any>, key: string) {
    if (!obj) {
      console.error("Object is undefined. Cannot lookup key.");
      console.error(obj);
      return undefined;
    }
    return obj[key];
  }
);

Handlebars.registerHelper("latexClean", function (text: string) {
  return text
    .replace(/&#x27;/g, "'") // Escape backslashes
    .replace(/&/g, "\\&")
    .replace(/%/g, "\\%")
    .replace(/#/g, "\\#")
    .replace(/_/g, "\\_");
});

Handlebars.registerHelper("snakeToPascalSpace", function (text: string) {
  return text
    .replace(/_/g, " ")
    .replace(/\b\w/g, function (char) {
      return char.toUpperCase();
    });
});

Handlebars.registerHelper("snakeToTildeSpace", function (text: string) {
  return text
    .replace(/_/g, "~")
    .replace(/\b\w/g, function (char) {
      return char.toUpperCase();
    });
});

Handlebars.registerHelper("enumerate", function (array: any[]) {
  return array.map((item, index) => {
    return { index: index, value: item };
  });
});

Handlebars.registerHelper("labSheetCompoundSpaces", function (array: any[]) {
  if(!array) {
    console.error("No compounds in the lab sheet.");
    return "";
  }
  if(array.length > 24) {
    console.error("Too many compounds in the lab sheet. Maximum is 24.");
  };
  let cells:string[]= array.map((item, index) => {
      return "\\scriptsize "+item;
  });
  while (cells.length < 24) {
    cells.push(" ");
  }
  let row1 = cells.slice(0, 12).join(" & ");
  let row2 = cells.slice(12, 24).join(" & ");
  return new Handlebars.SafeString(row1 + " \\\\[0.66cm] \\hline " + row2 + " \\\\[0.66cm] \\hline ");
});

Handlebars.registerHelper("trialLabSheetCompoundSpaces", function (array: any[]) {
  if(!array) {
    console.error("No compounds in the lab sheet.");
    return "";
  }
  if(array.length > 8) {
    console.error("Too many compounds in the lab sheet. Maximum is 8.");
  };
  let cells:string[]= array.map((item, index) => {
      return "\\scriptsize "+item;
  });
  while (cells.length < 8) {
    cells.push(" ");
  }
  let row1 = cells.slice(0, 4).join(" & ");
  let row2 = cells.slice(4, 8).join(" & ");
  return new Handlebars.SafeString(row1 + " \\\\[0.66cm] \\hline " + row2 + " \\\\[0.66cm] \\hline ");
});


export class LatexRenderer {
  static populateTemplate(
    latexFilePath: string,
    interface_data: any,
    output: string
  ): string {
    let templateContent = fs.readFileSync(latexFilePath, "utf-8");
    // Remove bindings
    const regex = bindingRegex.binding;
    templateContent = templateContent.replace(regex, "");
    const template = Handlebars.compile(templateContent);
    const renderedLatex = template(interface_data);

    const outputFilePath = output.replace(".pdf", ".tex");
    fs.writeFileSync(outputFilePath, renderedLatex);
    return outputFilePath;
  }
}
